 1	import * as React from 'react';
 2	
 3	export const useOutsideClickEvent = (onClickOutside: () => void) => {
 4	  const ref = React.useRef<HTMLDivElement>(null);
 5	
 6	  React.useEffect(() => {
 7	    /**
 8	     * Alert if clicked on outside of element
 9	     */
10	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
11	    function handleClickOutside(event: any) {
12	      if (ref.current && !ref.current.contains(event.target)) {
13	        // Don't close if clicking on a PatternFly menu/dropdown that's rendered via portal
14	        const target = event.target;
15	        const isPatternFlyMenu =
16	          target instanceof Element &&
17	          target.closest('.pf-v6-c-menu, .pf-v5-c-select__menu, .pf-v6-c-menu, .pf-v5-c-select__menu');
18	
19	        if (!isPatternFlyMenu) {
20	          onClickOutside();
21	        }
22	      }
23	    }
24	    // Bind the event listener
25	    document.addEventListener('mousedown', handleClickOutside);
26	    return () => {
27	      // Unbind the event listener on clean up
28	      document.removeEventListener('mousedown', handleClickOutside);
29	    };
30	  }, [onClickOutside, ref]);
31	
32	  return ref;
33	};

